mapper.select:
SELECT user_id ,user_nm FROM ad_user_mst WHERE 1=1 AND use_yn != 'N' AND del_yn != 'Y'
AND user_id = #{userId}
ORDER BY user_nm

SELECT a.user_id ,b.user_nm ,TO_CHAR(a.user_conn_date,'YYYY.MM.DD HH24:MI') user_conn_date ,a.user_conn_ipaddr ,a.user_work_fg_cd ,c.cd_nm user_work_fg_nm ,a.user_work_cts ,d.cd_nm edmp_mgmt_nm FROM ad_user_conn_log a ,ad_user_mst b ,ad_comm_cd c ,(select * from ad_comm_cd where comm_grp_cd = 'EDMP_MGMT_CD') d WHERE 1=1 AND a.user_id = b.user_id AND a.user_work_fg_cd = c.comm_cd AND a.edmp_mgmt_cd = d.comm_cd(+) AND b.use_yn != 'N' AND c.use_yn != 'N' AND c.comm_grp_cd = 'USER_WORK_FG_CD'
AND a.user_conn_date < TO_DATE(#{startDt}||'23:59:59','yyyyMMdd HH24:MI:SS')
AND a.user_conn_date > TO_DATE(#{startDt}||'23:59:59','yyyyMMdd HH24:MI:SS')
AND a.user_conn_date between TO_DATE(#{startDt}||'00:00:00','yyyyMMdd HH24:MI:SS') and TO_DATE(#{endDt}||'23:59:59','yyyyMMdd HH24:MI:SS')
AND a.user_conn_date between TO_DATE(#{startDt}||'00:00:00','yyyyMMdd HH24:MI:SS') and TO_DATE(#{startDt}||'23:59:59','yyyyMMdd HH24:MI:SS')
AND a.user_work_fg_cd = #{selectWorkFg}
AND a.edmp_mgmt_cd = #{selectSystem}
AND b.user_nm LIKE '%' || #{userNm} || '%'
ORDER BY a.user_conn_date DESC
#{endRow}
#{startRow}

SELECT /*+ PARALLEL(4) */ COUNT(*) OVER() AS TOTAL , ah.seq_id , ah.stm_cd , (select cd_nm from ad_comm_cd where comm_cd = ah.stm_cd and comm_grp_cd = 'STM_CD') stmNm , ah.alrm_nm , ah.alrm_note , ah.alrm_cts , ah.alrm_lvl_cd , (SELECT cd_nm FROM ad_comm_cd WHERE comm_cd = ah.alrm_lvl_cd and comm_grp_cd = 'ALRM_LVL_CD') alrmLvlNm , ah.alrm_tgt_addr , ah.stm_fir_reg_date , ah.stm_fir_reg_user_id , ah.stm_last_upd_date , ah.stm_last_upd_user_id FROM ad_stm_alrm_hst ah
WHERE 1=1
AND ah.stm_fir_reg_date < TO_DATE(#{startDt}||'23:59:59','yyyyMMdd HH24:MI:SS')
AND ah.stm_fir_reg_date > TO_DATE(#{startDt}||'23:59:59','yyyyMMdd HH24:MI:SS')
AND ah.stm_fir_reg_date between TO_DATE(#{startDt}||'00:00:00','yyyyMMdd HH24:MI:SS') and TO_DATE(#{endDt}||'23:59:59','yyyyMMdd HH24:MI:SS')
AND ah.stm_cd = #{stmCd}
AND ah.ALRM_LVL_CD = #{alrmLvlCd}
ORDER BY ah.seq_id DESC
#{endRow}
#{startRow}
